# Issue Title
Microsoft.Windows.Compatability external function CreateSymbolicLink() throws marshal error 2

# General

While attempting to createa a symbolic link by invoking `kernel32` and the external bool `CreateSymbolicLink`, it always returns false and throws Marshal 2 - ERROR_FILE_NOT_FOUND.

# Environment
Operating System: Windows 10
SDK: 2.1.300
IDE: JetBrains Rider 2018.1.4


# Details
For work, I've created a simple library to handle the creation of symbolic links for each individual environment using the following Interface:
```csharp
namespace Spectero.daemon.Libraries.Symlink
{
    
    /// <summary>
    /// This interface file defines a basic layout that each environment should be implemented to.
    /// </summary>
    public interface ISymlinkEnvironment
    {
        bool Create(string symlink, string absolutePath);
        bool Delete(string symlink);
    }
}
```

For windows specifically, we have the following class that is supposed to act as a form of wrapper to create these symbolic links as needed:
```csharp
namespace Spectero.daemon.Libraries.Symlink
{
    public class Windows : ISymlinkEnvironment
    {
        /// <summary>
        /// The parent class is the class that will initialize this environment.
        /// </summary>
        private Symlink _parent;

        /// <summary>
        /// Constructor
        /// (Inherits the parent class)
        /// </summary>
        /// <param name="parent"></param>
        public Windows(Symlink parent)
        {
            _parent = parent;
        }
        
        static extern bool CreateSymbolicLink(string lpSymlinkFileName, string lpTargetFileName, Symlink.SymbolicLink dwFlags);

        /// <summary>
        /// Wrapper function to create symlink and determine the type from the absolute path.
        /// 0 = file
        /// 1 = directory
        /// </summary>
        /// <param name="symlink"></param>
        /// <param name="absolutePath"></param>
        /// <returns></returns>
        public bool Create(string symlink, string absolutePath)
        {
            return CreateSymbolicLink(symlink, absolutePath, _parent.GetAbsolutePathType(absolutePath));
        }

        /// <summary>
        /// Delete the symlink safely.
        /// </summary>
        /// <param name="linkPath"></param>
        /// <returns></returns>
        /// <exception cref="Exception"></exception>
        public bool Delete(string linkPath)
        {
            if (_parent.IsSymlink(linkPath))
            {
                switch (_parent.GetAbsolutePathType(linkPath))
                {
                    case Symlink.SymbolicLink.Directory:
                        Directory.Delete(linkPath);
                        return true;

                    case Symlink.SymbolicLink.File:
                        File.Delete(linkPath);
                        return true;

                    default:
                        return false;
                }
            }
            else
            {
                throw new Exception("Specified deletion path is not a symbolic link.");
            }
        }
    }
}
```

And lastly, the management class that initializes each environment based on what the operating system environment is:
```csharp
namespace Spectero.daemon.Libraries.Symlink
{
    public class Symlink
    {
        private ISymlinkEnvironment _environment;

        public enum SymbolicLink
        {
            File = 0,
            Directory = 1
        }

        public Symlink()
        {
            if (AppConfig.isWindows) _environment = new Windows(this);
            if (AppConfig.isUnix) _environment = new Unix(this);
        }

        public SymbolicLink GetAbsolutePathType(string absolutePath)
        {
            // Check if file.
            if (File.Exists(absolutePath))
                return SymbolicLink.File;

            // Check if directory
            if (Directory.Exists(absolutePath))
                return SymbolicLink.Directory;

            // Unsure, we should never reach this point but let's decide to use a file.
            return SymbolicLink.File;
        }

        public bool IsSymlink(string linkPath)
        {
            FileInfo pathInfo = new FileInfo(linkPath);
            return pathInfo.Attributes.HasFlag(FileAttributes.ReparsePoint);
        }

        public ISymlinkEnvironment Environment => _environment;
    }
}
```


